declare const require: any;
declare const process: any;
const fs = require('node:fs');
const CsvParser = require('./csv').CsvParser;

if (process.argv[2] === 'parse') {
  if (!process.argv.includes('--input')) {
    console.error('Usage: node dist/cli.js parse --input <file>');
    process.exit(1);
  }

  const inputFilePath = process.argv[process.argv.indexOf('--input') + 1];
  const fileContent = fs.readFileSync(inputFilePath, 'utf-8');
  const csvParser = new CsvParser();
  const parsedData = csvParser.parse(fileContent);
  console.log(JSON.stringify(parsedData, null, 2));
} else if (process.argv[2] === 'stats') {
  if (!process.argv.includes('--input')) {
    console.error('Usage: node dist/cli.js stats --input <file>');
    process.exit(1);
  }

  const inputFilePath = process.argv[process.argv.indexOf('--input') + 1];
  const fileContent = fs.readFileSync(inputFilePath, 'utf-8');
  const csvParser = new CsvParser();
  const parsedData = csvParser.parse(fileContent);
  console.log(`Number of rows: ${parsedData.length}`);
} else if (process.argv[2] === '--help') {
  console.log('Usage: node dist/cli.js <command> [options]');
  console.log('\nCommands:');
  console.log('  parse   Parse CSV file and output JSON');
  console.log('  stats   Get statistics about the CSV file');
  console.log('\nOptions:');
  console.log('  --input <file>  Input CSV file path');
  process.exit(0);
} else {
  console.error('Unknown command. Use --help for more information.');
  process.exit(1);
}
